mapper.select:
SELECT COUNT(*) FROM STAGE_PREFER
WHERE MEMBER_NO = #{memberNo}
AND STAGE_NO = #{stageNo}
AND PREFER_TYPE = #{preferType}

mapper.delete:
DELETE FROM STAGE_PREFER
WHERE MEMBER_NO = #{memberNo}
AND STAGE_NO = #{stageNo}
AND PREFER_TYPE = #{preferType}

DELETE FROM STAGE_PREFER
WHERE MEMBER_NO = #{memberNo}
AND STAGE_NO = #{stageNo}
AND PREFER_TYPE != #{preferType}

